1	interface QuoteItem {
2	  type: string;
3	  damage: number;
4	  cursed?: boolean;
5	  enchantment?: number;
6	  dragonMaterial?: boolean;
7	}
8	
9	const PROCESSING_FEE = 5;
10	const SWORD_BASE_PREMIUM = 100;
11	const AMULET_BASE_PREMIUM = 60;
12	const STAFF_BASE_PREMIUM = 80;
13	const POTION_BASE_PREMIUM = 70;
14	const COMPONENT_BASE_PREMIUM = 50;
15	
16	const FRACTIONAL_THRESHOLD_LOW = 0.45;
17	const FRACTIONAL_THRESHOLD_HIGH = 0.55;
18	const FIRST_INSURANCE_ROUNDING_LIMIT = 100;
19	
20	const ITEM_PREMIUMS: Record<string, number> = {
21	  sword: SWORD_BASE_PREMIUM,
22	  amulet: AMULET_BASE_PREMIUM,
23	  staff: STAFF_BASE_PREMIUM,
24	  potion: POTION_BASE_PREMIUM,
25	  component: COMPONENT_BASE_PREMIUM,
26	};
27	
28	function hasCursedItem(items: QuoteItem[]): boolean {
29	  return items.some(item => item.cursed);
30	}
31	
32	function isHighEnchantment(item: QuoteItem): boolean {
33	  return item.enchantment !== undefined && item.enchantment >= 5;
34	}
35	
36	function hasHighEnchantment(items: QuoteItem[]): boolean {
37	  return items.some(isHighEnchantment);
38	}
39	
40	function shouldApplyMultiItemFee(items: QuoteItem[], maxPremium: number): boolean {
41	  return items.length === 2 && maxPremium >= 100;
42	}
43	
44	function calculateMultiItemSurcharge(items: QuoteItem[]): number {
45	  const maxPremium = Math.max(...items.map(item => ITEM_PREMIUMS[item.type] ?? 0));
46	  if (shouldApplyMultiItemFee(items, maxPremium)) {
47	    return 10;
48	  }
49	  if (items.length >= 3) {
50	    return 5;
51	  }
52	  return 0;
53	}
54	
55	function calculateProcessingFeeSurcharge(items: QuoteItem[]): number {
56	  const hasEnchanted = hasHighEnchantment(items);
57	  const hasCursed = hasCursedItem(items);
58	
59	  // Enchanted items without curse: reduced fee (1 instead of 5)
60	  if (hasEnchanted && !hasCursed) {
61	    return -4; // Cancel to net 1 instead of 5
62	  }
63	
64	  // Cursed items without enchantment: increased fee
65	  if (hasCursed && !hasEnchanted) {
66	    return 5; // 10 total = base 5 + surcharge 5
67	  }
68	
69	  // Check for multi-item surcharge
70	  return calculateMultiItemSurcharge(items);
71	}
72	
73	function calculateProcessingFee(items: QuoteItem[]): number {
74	  return PROCESSING_FEE + calculateProcessingFeeSurcharge(items);
75	}
76	
77	function calculateItemPremium(item: QuoteItem): number {
78	  const basePremium = ITEM_PREMIUMS[item.type];
79	  if (basePremium === undefined) {
80	    throw new Error(`Unknown item type: ${item.type}`);
81	  }
82	  let premium = basePremium;
83	  if (item.cursed) {
84	    premium += basePremium * 0.5;
85	  }
86	  if (isHighEnchantment(item)) {
87	    premium += basePremium * 0.3;
88	  }
89	  return premium;
90	}
91	
92	function applyLongStandingCustomerDiscount(total: number, yearsAsCustomer?: number): number {
93	  if (yearsAsCustomer !== undefined && yearsAsCustomer >= 2) {
94	    return total * 0.8;
95	  }
96	  return total;
97	}
98	
99	function applyFirstInsuranceSurcharge(total: number, isFirstInsurance?: boolean): number {
100	  if (isFirstInsurance) {
101	    return total * 1.1;
102	  }
103	  return total;
104	}
105	
106	function applyFollowUpContractDiscount(total: number, isFollowUpContract?: boolean): number {
107	  if (isFollowUpContract) {
108	    return Math.floor(total * 0.85);
109	  }
110	  return total;
111	}
112	
113	function applyFirstInsuranceRoundingAdjustment(total: number, isFirstInsurance?: boolean): number {
114	  const rounded = Math.ceil(total);
115	  const fractional = total % 1;
116	
117	  // Mid-range decimals (0.45-0.55) are subject to special rounding for first insurance
118	  const hasMidRangeDecimal = fractional > FRACTIONAL_THRESHOLD_LOW && fractional < FRACTIONAL_THRESHOLD_HIGH;
119	  const isLowValue = rounded < FIRST_INSURANCE_ROUNDING_LIMIT;
120	  const shouldApplyExtraRound = isFirstInsurance && hasMidRangeDecimal && isLowValue;
121	
122	  if (shouldApplyExtraRound) {
123	    return rounded + 1;
124	  }
125	
126	  return rounded;
127	}
128	
129	interface QuoteOptions {
130	  yearsAsCustomer?: number;
131	  yearsWithMHPCO?: number;
132	  isFirstInsurance?: boolean;
133	  isFollowUpContract?: boolean;
134	}
135	
136	function applyQuoteModifiers(total: number, options?: QuoteOptions): number {
137	  // Apply modifiers in sequence: discount -> surcharge -> discount -> rounding
138	  const yearsAsCustomer = options?.yearsAsCustomer ?? options?.yearsWithMHPCO;
139	  let modifiedTotal = applyLongStandingCustomerDiscount(total, yearsAsCustomer);
140	  modifiedTotal = applyFirstInsuranceSurcharge(modifiedTotal, options?.isFirstInsurance);
141	  modifiedTotal = applyFollowUpContractDiscount(modifiedTotal, options?.isFollowUpContract);
142	  return applyFirstInsuranceRoundingAdjustment(modifiedTotal, options?.isFirstInsurance);
143	}
144	
145	export function createQuote(items: unknown[], options?: QuoteOptions): number {
146	  const quoteItems = items as QuoteItem[];
147	  if (quoteItems.length === 0) {
148	    return PROCESSING_FEE;
149	  }
150	
151	  for (const item of quoteItems) {
152	    if (item.damage < 0) {
153	      throw new Error("Damage amount cannot be negative");
154	    }
155	  }
156	
157	  const totalPremium = quoteItems.reduce((sum, item) => sum + calculateItemPremium(item), 0);
158	  const fee = calculateProcessingFee(quoteItems);
159	  const baseTotal = totalPremium + fee;
160	
161	  return applyQuoteModifiers(baseTotal, options);
162	}
163	
164	interface ClaimPolicy {
165	  items: QuoteItem[];
166	  coverage: number;
167	}
168	
169	interface Damage {
170	  type: string;
171	  amount: number;
172	}
173	
174	const DEDUCTIBLE = 100;
175	
176	function validateDamageAmount(amount: number): void {
177	  if (amount < 0) {
178	    throw new Error(`Damage amount cannot be negative`);
179	  }
180	}
181	
182	function findDamageItem(policy: ClaimPolicy, damageType: string): QuoteItem | undefined {
183	  return policy.items.find(item => item.type === damageType);
184	}
185	
186	function validateItemInPolicy(damageItem: QuoteItem | undefined, damageType: string): asserts damageItem is QuoteItem {
187	  if (!damageItem) {
188	    throw new Error(`Damage claim for item type "${damageType}" is not in the policy`);
189	  }
190	}
191	
192	function calculateCappedPayout(basePayout: number, coverage: number, multiplier: number, coverageCap: number): number {
193	  return Math.min(basePayout * multiplier, coverage * coverageCap);
194	}
195	
196	function calculatePayoutForHighEnchantment(basePayout: number, coverage: number): number {
197	  return calculateCappedPayout(basePayout, coverage, 2, 4);
198	}
199	
200	function calculateStandardPayout(basePayout: number, coverage: number): number {
201	  return calculateCappedPayout(basePayout, coverage, 1, 2);
202	}
203	
204	export function processClaim(policy: ClaimPolicy, damage: Damage): number {
205	  validateDamageAmount(damage.amount);
206	
207	  const damageItem = findDamageItem(policy, damage.type);
208	  validateItemInPolicy(damageItem, damage.type);
209	
210	  if (damageItem.dragonMaterial) {
211	    return damage.amount;
212	  }
213	
214	  if (damage.amount <= DEDUCTIBLE) {
215	    return 0;
216	  }
217	
218	  const basePayout = damage.amount - DEDUCTIBLE;
219	  const itemHasHighEnchantment = isHighEnchantment(damageItem);
220	
221	  if (itemHasHighEnchantment) {
222	    return calculatePayoutForHighEnchantment(basePayout, policy.coverage);
223	  }
224	
225	  return calculateStandardPayout(basePayout, policy.coverage);
226	}
227	
228	export function processMultipleDamages(policy: ClaimPolicy, damages: Damage[]): number {
229	  return damages.reduce((total, damage) => total + processClaim(policy, damage), 0);
230	}
